import java.util.ArrayList;

class HashTable {
    private ArrayList<ArrayList<Object[]>> table;
    private int size;

    public HashTable(int size) {
        this.size = size;
        this.table = new ArrayList<>();
        for (int i = 0; i < size; i++) {
            table.add(new ArrayList<>());
        }
    }

    private int hash(String key) {
        int hash = 0;
        for (char c : key.toCharArray()) {
            hash += c;
        }
        return hash % size;
    }

    public void insert(String key, Object value) {
        int index = hash(key);
        for (Object[] item : table.get(index)) {
            if (item[0].equals(key)) {
                item[1] = value;
                return;
            }
        }
        table.get(index).add(new Object[]{key, value});
    }

    public Object get(String key) {
        int index = hash(key);
        for (Object[] item : table.get(index)) {
            if (item[0].equals(key)) {
                return item[1];
            }
        }
        return null;
    }

    public boolean delete(String key) {
        int index = hash(key);
        for (int i = 0; i < table.get(index).size(); i++) {
            if (table.get(index).get(i)[0].equals(key)) {
                table.get(index).remove(i);
                return true;
            }
        }
        return false;
    }

    public String toString() {
        StringBuilder result = new StringBuilder("{");
        boolean first = true;
        for (ArrayList<Object[]> bucket : table) {
            for (Object[] item : bucket) {
                if (!first) result.append(", ");
                result.append(item[0]).append(": ").append(item[1]);
                first = false;
            }
        }
        return result.append("}").toString();
    }
}

class HashTableExample {
    public static void main(String[] args) {
        HashTable ht = new HashTable(10);
        ht.insert("name", "Alice");
        ht.insert("age", 25);
        System.out.println("HashTable after insert: " + ht);
        System.out.println("Get name: " + ht.get("name"));
        ht.delete("age");
        System.out.println("HashTable after delete: " + ht);
    }
}
