#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX_SIZE 10
#define MAX_KEY_LEN 100

typedef struct Item {
    char key[MAX_KEY_LEN];
    char* value;
} Item;

typedef struct HashTable {
    Item* table[MAX_SIZE];
    int size;
} HashTable;

void initHashTable(HashTable* ht) {
    ht->size = MAX_SIZE;
    for (int i = 0; i < MAX_SIZE; i++) {
        ht->table[i] = NULL;
    }
}

unsigned int hash(const char* key, int size) {
    unsigned int hash = 0;
    for (int i = 0; key[i]; i++) {
        hash += key[i];
    }
    return hash % size;
}

void insert(HashTable* ht, const char* key, const char* value) {
    int index = hash(key, ht->size);
    if (ht->table[index] != NULL) {
        free(ht->table[index]->value);
        ht->table[index]->value = strdup(value);
        return;
    }
    Item* item = (Item*)malloc(sizeof(Item));
    strncpy(item->key, key, MAX_KEY_LEN);
    item->value = strdup(value);
    ht->table[index] = item;
}

char* get(HashTable* ht, const char* key) {
    int index = hash(key, ht->size);
    if (ht->table[index] != NULL && strcmp(ht->table[index]->key, key) == 0) {
        return ht->table[index]->value;
    }
    return NULL;
}

int delete(HashTable* ht, const char* key) {
    int index = hash(key, ht->size);
    if (ht->table[index] != NULL && strcmp(ht->table[index]->key, key) == 0) {
        free(ht->table[index]->value);
        free(ht->table[index]);
        ht->table[index] = NULL;
        return 1;
    }
    return 0;
}

void printHashTable(HashTable* ht) {
    printf("{");
    int first = 1;
    for (int i = 0; i < ht->size; i++) {
        if (ht->table[i] != NULL) {
            if (!first) printf(", ");
            printf("%s: %s", ht->table[i]->key, ht->table[i]->value);
            first = 0;
        }
    }
    printf("}\n");
}

