    HashTable ht;
    initHashTable(&ht);
    insert(&ht, "name", "Alice");
    insert(&ht, "age", "25");
    printf("HashTable after insert: ");
    printHashTable(&ht);
    printf("Get name: %s\n", get(&ht, "name"));
    delete(&ht, "age");
    printf("HashTable after delete: ");
    printHashTable(&ht);
    return 0;
}
