using System;
using System.Collections.Generic;

class HashTable {
    private List<KeyValuePair<string, object>>[] table;
    private int size;

    public HashTable(int size = 10) {
        this.size = size;
        this.table = new List<KeyValuePair<string, object>>[size];
        for (int i = 0; i < size; i++) {
            table[i] = new List<KeyValuePair<string, object>>();
        }
    }

    private int Hash(string key) {
        int hash = 0;
        foreach (char c in key) {
            hash += c;
        }
        return hash % size;
    }

    public void Insert(string key, object value) {
        int index = Hash(key);
        foreach (var item in table[index]) {
            if (item.Key == key) {
                table[index].Remove(item);
                break;
            }
        }
        table[index].Add(new KeyValuePair<string, object>(key, value));
    }

    public object Get(string key) {
        int index = Hash(key);
        foreach (var item in table[index]) {
            if (item.Key == key) {
                return item.Value;
            }
        }
        return null;
    }

    public bool Delete(string key) {
        int index = Hash(key);
        for (int i = 0; i < table[index].Count; i++) {
            if (table[index][i].Key == key) {
                table[index].RemoveAt(i);
                return true;
            }
        }
        return false;
    }

    public Dictionary<string, object> ToDictionary() {
        var result = new Dictionary<string, object>();
        foreach (var bucket in table) {
            foreach (var item in bucket) {
                result[item.Key] = item.Value;
            }
        }
        return result;
    }
}

class Program {
    static void Main() {
        HashTable ht = new HashTable();
        ht.Insert("name", "Alice");
        ht.Insert("age", 25);
        Console.WriteLine("HashTable after insert: {{ " + string.Join(", ", ht.ToDictionary().Select(kv => $"{kv.Key}: {kv.Value}")) + " }}");
        Console.WriteLine("Get name: " + ht.Get("name"));
        ht.Delete("age");
        Console.WriteLine("HashTable after delete: {{ " + string.Join(", ", ht.ToDictionary().Select(kv => $"{kv.Key}: {kv.Value}")) + " }}");
    }
}
// Output: HashTable after insert: { name: Alice, age: 25 }
// Output: Get name: Alice
// Output: HashTable after delete: { name: Alice }

