#include <iostream>
#include <vector>
#include <string>

class HashTable {
private:
    std::vector<std::vector<std::pair<std::string, std::string>>> table;
    int size;

public:
    HashTable(int size = 10) : size(size) {
        table.resize(size);
    }

    int hash(const std::string& key) {
        int hash = 0;
        for (char c : key) {
            hash += c;
        }
        return hash % size;
    }

    void insert(const std::string& key, const std::string& value) {
        int index = hash(key);
        for (auto& item : table[index]) {
            if (item.first == key) {
                item.second = value;
                return;
            }
        }
        table[index].push_back({key, value});
    }

    std::string get(const std::string& key) {
        int index = hash(key);
        for (const auto& item : table[index]) {
            if (item.first == key) {
                return item.second;
            }
        }
        return "";
    }

    bool remove(const std::string& key) {
        int index = hash(key);
        for (auto it = table[index].begin(); it != table[index].end(); ++it) {
            if (it->first == key) {
                table[index].erase(it);
                return true;
            }
        }
        return false;
    }

    void print() {
        std::cout << "{";
        bool first = true;
        for (const auto& bucket : table) {
            for (const auto& item : bucket) {
                if (!first) std::cout << ", ";
                std::cout << item.first << ": " << item.second;
                first = false;
            }
        }
        std::cout << "}\n";
    }
};

int main() {
    HashTable ht;
    ht.insert("name", "Alice");
    ht.insert("age", "25");
    std::cout << "HashTable after insert: ";
    ht.print();
    std::cout << "Get name: " << ht.get("name") << "\n";
    ht.remove("age");
    std::cout << "HashTable after delete: ";
    ht.print();
    return 0;
}
// Output: HashTable after insert: {name: Alice, age: 25}
// Output: Get name: Alice
// Output: HashTable after delete: {name: Alice}

